&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/23/11/F1_Other_Arbaz__30-10-23_D12.png&quot; style=&quot;width: 221px; height: 132px;&quot; /&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Calculation&lt;/strong&gt; &lt;strong&gt;:&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;According to question,&lt;/p&gt;

&lt;p&gt;&amp;rArr;&amp;nbsp;&amp;ang;PAB = 65&amp;deg;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;Now In&amp;nbsp;&amp;Delta;APB,&lt;/p&gt;

&lt;p&gt;&amp;rArr;&amp;nbsp;&amp;ang;A&amp;nbsp; +&amp;nbsp;&amp;ang;B +&amp;nbsp;&amp;ang;P = 180&amp;deg;&amp;nbsp;&lt;/p&gt;

&lt;p&gt;&amp;rArr; 65&amp;deg; +&amp;nbsp;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(33, 37, 41); --darkreader-inline-color: #d1cdc7;&quot;&gt;&amp;ang;B + 90&amp;deg; = 180&amp;deg;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(33, 37, 41); --darkreader-inline-color: #d1cdc7;&quot;&gt;&amp;rArr;&amp;nbsp;&amp;ang;B = 180&amp;deg; - 155&amp;deg; = 25&amp;deg;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span data-darkreader-inline-color=&quot;&quot; style=&quot;color: rgb(33, 37, 41); --darkreader-inline-color: #d1cdc7;&quot;&gt;&amp;there4; The correct answer is 25&amp;deg;.&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;<br><br>&lt;p&gt;&lt;strong&gt;प्रयुक्त अवधारणा:&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;किसी वृत्त की स्पर्श रेखा के &lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;स्पर्श&amp;nbsp;&lt;/span&gt;बिंदु पर बना कोण समकोण होता है।&lt;/p&gt;

&lt;p&gt;&lt;img alt=&quot;&quot; src=&quot;//storage.googleapis.com/tb-img/production/23/11/F1_Other_Arbaz__30-10-23_D12.png&quot; style=&quot;color: rgb(33, 37, 41); width: 221px; height: 132px;&quot; /&gt;&lt;span style=&quot;display: none;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;गणना:&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;प्रश्नानुसार,&lt;/p&gt;

&lt;p&gt;&amp;rArr; &amp;ang;PAB = 65&amp;deg;&lt;/p&gt;

&lt;p&gt;अब &amp;Delta;APB में,&lt;/p&gt;

&lt;p&gt;&amp;rArr; &amp;ang;A + &amp;ang;B + &amp;ang;P = 180&amp;deg;&lt;/p&gt;

&lt;p&gt;&amp;rArr; 65&amp;deg; + &amp;ang;B + 90&amp;deg; = 180&amp;deg;&lt;/p&gt;

&lt;p&gt;&amp;rArr; &amp;ang;B = 180&amp;deg; - 155&amp;deg; = 25&amp;deg;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&amp;there4; सही उत्तर 25&amp;deg; है।&lt;/strong&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Given:&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;Total votes is 12000&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;One candidate gets 60&amp;nbsp;percent of valid votes&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;90 percent votes are valid&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Concept:&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;Valid votes percent + invalid votes percent = 100%&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;If one candidate gets x percent valid votes other candidate should get (100 &amp;ndash; x) percent valid votes.&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;Calculation:&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;Valid votes = 90% of 12000 = 10800&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;Votes other candidate gets = (100 - 60)% of valid votes&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; 40/100&amp;nbsp;&amp;times;&amp;nbsp;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;10800&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;color: rgb(33, 37, 41);&quot;&gt;&amp;rArr; 4320&lt;/span&gt;&lt;/p&gt;

&lt;p style=&quot;color: rgb(33, 37, 41);&quot;&gt;&lt;span style=&quot;font-weight: bolder;&quot;&gt;&amp;there4;&lt;/span&gt;&amp;nbsp;&amp;nbsp;&lt;span style=&quot;font-weight: bolder;&quot;&gt;The other candidate got 4320 votes.&lt;/span&gt;&lt;/p&gt;<br><br>&lt;p&gt;&lt;strong&gt;दिया गया है:&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;कुल मत 12000 थे।&lt;/p&gt;

&lt;p&gt;एक उम्मीदवार को वैध मतों के 60 प्रतिशत मत प्राप्त हुए।&lt;/p&gt;

&lt;p&gt;90 प्रतिशत मत वैध थे।&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;अवधारणा:&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;वैध मत प्रतिशत + अवैध मत प्रतिशत = 100%&lt;/p&gt;

&lt;p&gt;यदि एक उम्मीदवार को x प्रतिशत वैध मत प्राप्त होते&amp;nbsp;हैं तो दूसरे उम्मीदवार को (100 &amp;ndash; x) प्रतिशत वैध मत प्राप्त होने चाहिए।&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;गणना:&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;वैध मत = 12000 का 90% = 10800&lt;/p&gt;

&lt;p&gt;अन्य उम्मीदवार को प्राप्त मत = (100 - 60)% वैध मत&lt;/p&gt;

&lt;p&gt;&amp;rArr; 40/100 &amp;times; 10800&lt;/p&gt;

&lt;p&gt;&amp;rArr; 4320&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&amp;there4; दूसरे उम्मीदवार&lt;/strong&gt;&lt;strong&gt; को 4320 मत प्राप्त हुए।&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;Given:&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;x + y + z = 1, xy + yz + zx = xyz = -4&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;Formula used:&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;x&lt;sup&gt;3&lt;/sup&gt;&amp;nbsp;+ y&lt;sup&gt;3&lt;/sup&gt;&amp;nbsp;+ z&lt;sup&gt;3&lt;/sup&gt;&amp;nbsp;&lt;/span&gt;&amp;ndash;&amp;nbsp;3xyz = (x + y + z) [(x + y + z)&lt;sup&gt;2&lt;/sup&gt;&amp;nbsp;&amp;ndash;&amp;nbsp;3(xy + yz + zx)]&lt;/p&gt;

