&lt;p&gt;&amp;rArr; x&lt;sup&gt;3&lt;/sup&gt;&amp;nbsp;+ y&lt;sup&gt;3&lt;/sup&gt;&amp;nbsp;+ z&lt;sup&gt;3&lt;/sup&gt;&amp;nbsp;+ 12&amp;nbsp;= (1 + 12)&lt;/p&gt;

&lt;p&gt;&amp;rArr;&amp;nbsp;&lt;span style=&quot;&quot;&gt;x&lt;/span&gt;&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;3&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;+ y&lt;/span&gt;&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;3&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;+ z&lt;/span&gt;&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;3&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;+ 12&amp;nbsp;= 13&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&amp;rArr; x&lt;sup&gt;3&lt;/sup&gt;&amp;nbsp;+ y&lt;sup&gt;3&lt;/sup&gt;&amp;nbsp;+ z&lt;sup&gt;3&lt;/sup&gt;&amp;nbsp;= (13&amp;nbsp;&amp;ndash; 12)&lt;/p&gt;

&lt;p&gt;&amp;rArr;&amp;nbsp;&lt;span style=&quot;&quot;&gt;&amp;nbsp;(x&lt;/span&gt;&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;3&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;+ y&lt;/span&gt;&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;3&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;+ z&lt;/span&gt;&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;3&lt;/span&gt;&lt;span style=&quot;&quot;&gt;) = 1&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;strong&gt;&lt;span style=&quot;&quot;&gt;&amp;there4; The required value is 1&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;<br><br>&lt;p&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;दिया गया है:&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;x + y + z = 1, xy + yz + zx = xyz = -4&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;प्रयुक्त सूत्र:&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;x&lt;sup&gt;3&lt;/sup&gt;&amp;nbsp;+ y&lt;sup&gt;3&lt;/sup&gt;&amp;nbsp;+ z&lt;sup&gt;3&lt;/sup&gt;&amp;nbsp;&lt;/span&gt;&amp;ndash;&amp;nbsp;3xyz = (x + y + z) [(x + y + z)&lt;sup&gt;2&lt;/sup&gt;&amp;nbsp;&amp;ndash;&amp;nbsp;3(xy + yz + zx)]&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;font-weight: 700; &quot;&gt;गणना:&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;प्रश्न के अनुसार&lt;/span&gt;&lt;/p&gt;

&lt;p&gt;&lt;span style=&quot;&quot;&gt;x&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;3&lt;/span&gt;&amp;nbsp;+ y&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;3&lt;/span&gt;&amp;nbsp;+ z&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em;font-size:10.5px;&quot;&gt;3&lt;/span&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;ndash;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;3xyz = (x + y + z) [(x + y + z)&lt;/span&gt;&lt;span style=&quot; line-height: 0; position: relative; vertical-align: baseline; top: -0.5em; font-size:10.5px;&quot;&gt;2&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;&amp;ndash;&amp;nbsp;&lt;/span&gt;&lt;span style=&quot;&quot;&gt;3(xy + yz + zx)]&lt;/span&gt;&lt;/p&gt;

